import{_ as a,o as i,c as g,a3 as u}from"./chunks/framework.CGpxwYOt.js";const d=JSON.parse('{"title":"2.3 日常活动（daily）","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 游戏内每次经过日期刷新时间就可以接取任务的活动为日常活动。 日常活动按时间分为两种： ①游戏指定时间开始 ②现实指定时间开始 大部分日常活动可以在每日固定的日常活动团队中完成。一次最多2 ","frontmatter":{"title":"2.3 日常活动（daily）","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 游戏内每次经过日期刷新时间就可以接取任务的活动为日常活动。 日常活动按时间分为两种： ①游戏指定时间开始 ②现实指定时间开始 大部分日常活动可以在每日固定的日常活动团队中完成。一次最多2 ","outline":"deep"},"headers":[],"relativePath":"pve/2-3.md","filePath":"pve/2-3.md","lastUpdated":1782387794000}'),t={name:"pve/2-3.md"};function e(l,s,p,r,o,f){return i(),g("div",null,[...s[0]||(s[0]=[u('<h1 id="_2-3-日常活动-daily" tabindex="-1">2.3 日常活动（daily） <a id="s167-2f58b5b0"></a> <a class="header-anchor" href="#_2-3-日常活动-daily" aria-label="Permalink to &quot;2.3 日常活动（daily） &lt;a id=&quot;s167-2f58b5b0&quot;&gt;&lt;/a&gt;&quot;">​</a></h1><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><h2 id="_2-3-1-什么是日常活动" tabindex="-1">2.3.1 什么是日常活动 <a id="s168-f48edfd8"></a> <a class="header-anchor" href="#_2-3-1-什么是日常活动" aria-label="Permalink to &quot;2.3.1 什么是日常活动 &lt;a id=&quot;s168-f48edfd8&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>游戏内每次经过日期刷新时间就可以接取任务的活动为日常活动。</p><h2 id="_2-3-2-日常活动的种类" tabindex="-1">2.3.2 日常活动的种类 <a id="s169-7123212f"></a> <a class="header-anchor" href="#_2-3-2-日常活动的种类" aria-label="Permalink to &quot;2.3.2 日常活动的种类 &lt;a id=&quot;s169-7123212f&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>日常活动按时间分为两种：</p><p>①游戏指定时间开始</p><p>②现实指定时间开始</p><h2 id="_2-3-3-日常活动的参与" tabindex="-1">2.3.3 日常活动的参与 <a id="s170-3fb22497"></a> <a class="header-anchor" href="#_2-3-3-日常活动的参与" aria-label="Permalink to &quot;2.3.3 日常活动的参与 &lt;a id=&quot;s170-3fb22497&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>大部分日常活动可以在每日固定的日常活动团队中完成。一次最多2 个团队100人，满团的话一般只能等下一次了。</p><p>进入团队流程如下：</p><p>在游戏画面右下角找到该图标</p><p>或者使用快捷键shift+R 唤出团队界面，如下图：</p><p>红框内左下角是团长名字和等级，点击右边申请即可进团，如下：</p><p>蓝框处是你的职责（非PVP 团和BOSS 团不用管）</p><p>点击箭头指向红框处即可进团。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1972.jpeg" alt="图示：2.3.3 日常活动的参与" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1973.jpeg" alt="图示：2.3.3 日常活动的参与" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1982.jpeg" alt="图示：2.3.3 日常活动的参与" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1983.jpeg" alt="图示：2.3.3 日常活动的参与" loading="lazy"></figure><h2 id="_2-3-4-日常活动的收益" tabindex="-1">2.3.4 日常活动的收益 <a id="s171-d31e7f69"></a> <a class="header-anchor" href="#_2-3-4-日常活动的收益" aria-label="Permalink to &quot;2.3.4 日常活动的收益 &lt;a id=&quot;s171-d31e7f69&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>日常活动的主要收益是荣誉和瓶子选择箱子，其余的有完成每日挑战给的奖励，</p><p>工会每日任务给的奖励。还有就是日常活动BOSS 死亡后概率掉落的每人一份金箱子，</p><p>以及概率掉落团队roll 点的头领强化剂。</p><h2 id="_2-3-5-征兆-cr-与噩梦-gr" tabindex="-1">2.3.5 征兆（CR）与噩梦(GR) <a id="s172-b1333006"></a> <a class="header-anchor" href="#_2-3-5-征兆-cr-与噩梦-gr" aria-label="Permalink to &quot;2.3.5 征兆（CR）与噩梦(GR) &lt;a id=&quot;s172-b1333006&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>注意！！！征兆和噩梦BOSS 刷新时接到的任务，需要至少攻击一次BOSS 才能完成。</p><h3 id="征兆" tabindex="-1">征兆 <a id="s173-4b52db17"></a> <a class="header-anchor" href="#征兆" aria-label="Permalink to &quot;征兆 &lt;a id=&quot;s173-4b52db17&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>时间为游戏中午12：00 开始出怪。</p><p>西大陆可在十字星住民如下NPC 处接到任务：</p><p>东大陆可在伊尼斯住民或者卡诺维德的隐月抵抗军NPC 处接到任务。</p><p>征兆会在地图上3 个位置随机出怪，团长知道刷新位置后会标记。</p><p>十字星点位如下：</p><p>伊尼斯泰尔点位如下：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1989.jpeg" alt="图示：征兆" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1997.jpeg" alt="图示：征兆" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1998.jpeg" alt="图示：征兆" loading="lazy"></figure><h3 id="噩梦" tabindex="-1">噩梦 <a id="s174-c2af709b"></a> <a class="header-anchor" href="#噩梦" aria-label="Permalink to &quot;噩梦 &lt;a id=&quot;s174-c2af709b&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>任务只要游戏到晚上，西大陆就可以在十字星住民牌子处接任务，如下：</p><p>西大陆接到任务后前往监视者营地交任务，任务内容一般为随机10 个材料，提</p><p>交任务NPC 如下图：</p><p>游戏时间0：00 后，在十字星监视者营地蓝框位置位置会刷任务要求运送货物，</p><p>每人需要交2 个，你可以交其他玩家背过来放到地上的。蓝框位置即为货物刷新位置。</p><p>另外一个货物刷新如下图：</p><p>装上货物后，到十字星住民下面下图红框位置交互即可：</p><p>在1：00 前是不会刷怪的，也就是说你有现实时间10 分钟的时间去运货。</p><p>打完噩梦BOSS 后会出现一个塔（有炮车打才会打得快），打掉塔会出现2 个不同颜色的传送门，选择不同的传送门可以接到不同的任务（一天只能接一次，进过一次门，下次噩梦换下一个门是没用的）。传送门如下图：</p><p>红门任务如下：</p><p>绿门任务如下：</p><p>跳门打完怪和BOSS 后，原来2 个传送门位置会刷新最终BOSS，打完即可获得</p><p>5 阶段任务奖励。（！！！最新版已经合并为一个宝箱自己选择奖励）</p><p>东大陆噩梦前置任务在伊尼斯泰尔的卡诺维德接取，如下图：</p><p>东大陆提交任务和运送货物起始点为路口哨所。</p><p>运送目的地为修行者村上面。</p><p>NPC 及流程和西大陆差不多。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2003.jpeg" alt="图示：噩梦" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2004.jpeg" alt="图示：噩梦" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2010.jpeg" alt="图示：噩梦" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2011.jpeg" alt="图示：噩梦" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2016.jpeg" alt="图示：噩梦" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2017.jpeg" alt="图示：噩梦" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2022.jpeg" alt="图示：噩梦" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2023.jpeg" alt="图示：噩梦" loading="lazy"></figure><h2 id="_2-3-6-悉拉玛次元裂隙-hiram-rift" tabindex="-1">2.3.6 悉拉玛次元裂隙（hiram rift） <a id="s175-750b8975"></a> <a class="header-anchor" href="#_2-3-6-悉拉玛次元裂隙-hiram-rift" aria-label="Permalink to &quot;2.3.6 悉拉玛次元裂隙（hiram rift） &lt;a id=&quot;s175-750b8975&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>游戏内晚上9 点开始，可以在悉拉玛山脉西部的悉拉玛洞窟接任务。</p><p>！！！注意：海盗会有2 个任务，一个英文，一个中文。英文任务是每个小阶段任务都给觉醒卷轴，但是一共只给22 张，中文任务则是和东西大一样，做完4 个阶段小任务后给55 张觉醒卷轴和18 个次元古代强化剂</p><p>接任务NPC 如下：</p><p>活动开始时会随机在悉拉玛山脉西部或者东部刷新怪物，一共会刷新4 次。前三次的虚空吞噬者必定掉落虚空宝箱，概率掉落金箱子，最终首领BOSS 掉落次元宝箱。</p><p>内容如下：</p><p>小知识：虽然任务一天只能做一次，但是BOSS 掉落的宝箱每次都可以捡，也就是多混活动还是能混到5 个瓶子和卷轴（很少不太推荐就是了）。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2032.jpeg" alt="图示：2.3.6 悉拉玛次元裂隙（hiram rift）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2033.jpeg" alt="图示：2.3.6 悉拉玛次元裂隙（hiram rift）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2034.jpeg" alt="图示：2.3.6 悉拉玛次元裂隙（hiram rift）" loading="lazy"></figure><h3 id="悉拉玛山脉西部地图刷新点位及英文如下" tabindex="-1">悉拉玛山脉西部地图刷新点位及英文如下： <a id="s176-b0881281"></a> <a class="header-anchor" href="#悉拉玛山脉西部地图刷新点位及英文如下" aria-label="Permalink to &quot;悉拉玛山脉西部地图刷新点位及英文如下： &lt;a id=&quot;s176-b0881281&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>River 米内河下边</p><p>South Illusion 幻影洞窟右边</p><p>Ruins 悉拉玛卡</p><p>Illusion 娜刹什崇拜之地</p><h3 id="悉拉玛山脉东部地图刷新点位及英文如下" tabindex="-1">悉拉玛山脉东部地图刷新点位及英文如下： <a id="s177-d6888d8d"></a> <a class="header-anchor" href="#悉拉玛山脉东部地图刷新点位及英文如下" aria-label="Permalink to &quot;悉拉玛山脉东部地图刷新点位及英文如下： &lt;a id=&quot;s177-d6888d8d&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>Black 黑森林营地上方</p><p>Hall 勇士殿堂下方</p><p>Falls 阶梯瀑布下方</p><h2 id="_2-3-7-领地-castle" tabindex="-1">2.3.7 领地（castle） <a id="s178-f0e6c8cb"></a> <a class="header-anchor" href="#_2-3-7-领地-castle" aria-label="Permalink to &quot;2.3.7 领地（castle） &lt;a id=&quot;s178-f0e6c8cb&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>（海盗由于无法获取领地，无法做领地任务，不过海盗有别的任务补充，详细见</p><p>海盗每日部分）</p><p>每日任务团时间会有英雄开团带领大家完成50 个领地动物击杀任务领地运货任务和领地做货任务可以自行完成。</p><p>领地送货任务和领地缺少的货物任务需要在英雄开启后才能接取和完成。</p><p>领地击杀50 动物任务可以在图示位置接取：</p><p>领地运货任务可以在图示位置接取：</p><p>领地做货任务可以在图示位置接取：</p><p>交货仓库如下图：</p><p>领地还有2 个日常任务是用庭院生命体标本来提交的，其中一个是用10 个标本换取一个随机庭院植物种子。另外一个是根据领地情况来决定的（需要NPC 处于补给中），可能会出以下任务奖励：4 阶段古代卷轴、领地币。</p><p>标本换种子任务NPC 如下：</p><p>提交任务后会获得一个随机庭院植物种子，打开后就知道是什么花了，种需要在原大陆18h，会出15-25 朵花。</p><p>标本补给任务NPC 如下：</p><p>以下还有2 个任务是需要英雄开启的</p><p>1）领地缺少的物资</p><p>2）运送领地运输品</p><p>任务1）开启后，可以在下图NPC 处接任务：</p><p>然后去其他领地运来这个领地没有的物资（这个领地是泉水就运火木；是火木就</p><p>运泉水）</p><p>运到后走到NPC 后面的木堆，按F 交互放下物质后即可完成任务。</p><p>任务2）开启后，现在下图NPC 处接任务：</p><p>然后去做货任务交货的仓库里拿货，如下：</p><p>再接着就是运货到该领地的势力总部。</p><p>红框NPC 接任务。再到下图位置按F 即可完成任务。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2046.jpeg" alt="图示：2.3.7 领地（castle）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2047.jpeg" alt="图示：2.3.7 领地（castle）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2053.jpeg" alt="图示：2.3.7 领地（castle）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2054.jpeg" alt="图示：2.3.7 领地（castle）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2059.jpeg" alt="图示：2.3.7 领地（castle）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2064.jpeg" alt="图示：2.3.7 领地（castle）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2065.jpeg" alt="图示：2.3.7 领地（castle）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2070.jpeg" alt="图示：2.3.7 领地（castle）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2054.jpeg" alt="图示：2.3.7 领地（castle）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2075.jpeg" alt="图示：2.3.7 领地（castle）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2076.jpeg" alt="图示：2.3.7 领地（castle）" loading="lazy"></figure><h2 id="_2-3-8-悉拉玛山脉东部-mammoth-tree" tabindex="-1">2.3.8 悉拉玛山脉东部（mammoth/tree） <a id="s179-9006caaa"></a> <a class="header-anchor" href="#_2-3-8-悉拉玛山脉东部-mammoth-tree" aria-label="Permalink to &quot;2.3.8 悉拉玛山脉东部（mammoth/tree） &lt;a id=&quot;s179-9006caaa&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>东部日常任务为2 个BOSS 击杀任务。</p><p>也就是俗称的大树大象。每日任务团会做这些任务，没有赶上也可以让大佬带你击杀。</p><p>击杀大象任务可以在悉拉玛山脉东部的勇士殿堂处NPC 接取，如下图：</p><p>任务内容（已经改为20 个卷轴）如下：</p><p>击杀大树任务可以在悉拉玛山脉东部的黑森林营地处NPC 接取，如下图：</p><p>任务内容（已经改为20 个卷轴）如下：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2081.jpeg" alt="图示：2.3.8 悉拉玛山脉东部（mammoth/tree）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2082.jpeg" alt="图示：2.3.8 悉拉玛山脉东部（mammoth/tree）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2088.jpeg" alt="图示：2.3.8 悉拉玛山脉东部（mammoth/tree）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2082.jpeg" alt="图示：2.3.8 悉拉玛山脉东部（mammoth/tree）" loading="lazy"></figure><h2 id="_2-3-9-芦苇地与魔法之地" tabindex="-1">2.3.9 芦苇地与魔法之地 <a id="s180-2b43a225"></a> <a class="header-anchor" href="#_2-3-9-芦苇地与魔法之地" aria-label="Permalink to &quot;2.3.9 芦苇地与魔法之地 &lt;a id=&quot;s180-2b43a225&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>芦苇地和魔法之地每日任务的作用都是积累BOSS 挑战积分，BOSS 挑战积分达标后会直接开启BOSS 战，因此在最后一次任务团中请不要着急提交任务。</p><p>芦苇地任务可在下图NPC 处接取：</p><p>任务内容如下：</p><p>魔法之地任务可在下图NPC 处接取：</p><p>任务要求及奖励如下：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2093.jpeg" alt="图示：2.3.9 芦苇地与魔法之地" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2094.jpeg" alt="图示：2.3.9 芦苇地与魔法之地" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2100.jpeg" alt="图示：2.3.9 芦苇地与魔法之地" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2101.jpeg" alt="图示：2.3.9 芦苇地与魔法之地" loading="lazy"></figure><h2 id="_2-3-10-伊弗尼尔山" tabindex="-1">2.3.10 伊弗尼尔山 <a id="s181-2cf63f01"></a> <a class="header-anchor" href="#_2-3-10-伊弗尼尔山" aria-label="Permalink to &quot;2.3.10 伊弗尼尔山 &lt;a id=&quot;s181-2cf63f01&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>伊弗尼尔山的每日任务奖励是给箱子，如图：</p><p>开箱子可以获得娜刹什币，如下图：</p><p>继承者40~44 级情况下一个箱子给17 个币，45 级是18 个，每多提升5 级都可以多获得一个币，最高的继承者70 级一个箱子可以获得23 个币。</p><p>建议在伊弗尼尔之翼接取任务，这样子所有每日都可以接到。（因为敲蛋任务在其他3 个位置的NPC 那接不到）。可接取任务如下：</p><p>①调查浮空岛任务流程如下：</p><p>跳门后会出现在图示红框位置，然后顺着箭头走即可：</p><p>走到尽头后会有一个小房间，走到图示红框位置即可自动完成任务。</p><p>②调查转移现象（敲蛋任务），可在图示位置找到蛋。</p><p>红框和红圈处（平常推荐红框，娜刹什入侵时推荐红圈）：</p><p>靠近蛋后即可按F 敲蛋，敲够10 个就可以跳门回去伊弗尼尔之翼交任务了。</p><p>③和④虽然可以每天接，但是只有在娜刹什入侵的时候可以做。</p><p>伊弗尼尔山还可以用点券买一个月的每日任务，任务内容为打50 怪，奖励几个箱子，如果你比较肝又想快速提进度可以买一个。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2106.jpeg" alt="图示：2.3.10 伊弗尼尔山" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2107.jpeg" alt="图示：2.3.10 伊弗尼尔山" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2114.jpeg" alt="图示：2.3.10 伊弗尼尔山" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2115.jpeg" alt="图示：2.3.10 伊弗尼尔山" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2120.jpeg" alt="图示：2.3.10 伊弗尼尔山" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2121.jpeg" alt="图示：2.3.10 伊弗尼尔山" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2122.jpeg" alt="图示：2.3.10 伊弗尼尔山" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2127.jpeg" alt="图示：2.3.10 伊弗尼尔山" loading="lazy"></figure><h2 id="_2-3-11-娜刹什入侵与大草原神兽争夺战" tabindex="-1">2.3.11 娜刹什入侵与大草原神兽争夺战 <a id="s182-b4574d31"></a> <a class="header-anchor" href="#_2-3-11-娜刹什入侵与大草原神兽争夺战" aria-label="Permalink to &quot;2.3.11 娜刹什入侵与大草原神兽争夺战 &lt;a id=&quot;s182-b4574d31&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><h3 id="娜刹什入侵-invasion" tabindex="-1">娜刹什入侵（invasion） <a id="s183-cadacbf6"></a> <a class="header-anchor" href="#娜刹什入侵-invasion" aria-label="Permalink to &quot;娜刹什入侵（invasion） &lt;a id=&quot;s183-cadacbf6&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>每周一六晚上8：30 会开娜刹什入侵的团，西大陆负责支部开始的下半部分区域，</p><p>东大陆负责悼念碑开始的上半部分区域。</p><p>入侵剩余36：00 分会刷新入侵任务、光球、指南针和眼睛。除了入侵任务都可以提前接取。剩下28：59 分时会再刷新一次光球、指南针和眼睛。</p><p>光球如下图：</p><p>指南针如下图：</p><p>集合点是副官刷新位置，如下图：</p><p>21 分时会刷新入侵怪，跟着标记走即可。</p><p>混完任务后如果离胜利还比较久可以先跳门去支部等着，胜利后看看刷新的商人有没有你想买的东西。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2132.jpeg" alt="图示：娜刹什入侵（invasion）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2133.jpeg" alt="图示：娜刹什入侵（invasion）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2140.jpeg" alt="图示：娜刹什入侵（invasion）" loading="lazy"></figure><h3 id="大草原神兽争夺战" tabindex="-1">大草原神兽争夺战 <a id="s184-996d0427"></a> <a class="header-anchor" href="#大草原神兽争夺战" aria-label="Permalink to &quot;大草原神兽争夺战 &lt;a id=&quot;s184-996d0427&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>西部大草原进入战争后，玩家可以在各自的势力总部接取到2 个争夺战任务。</p><p>注意！！！需要装评达到11000 分</p><p>然后就跟着大部队刷怪就行，挂机也记得不要暂离！</p><p>完成任务会加胜利进度，剩下等大部队养神兽就行，分数达到胜利要求后即可获得15 个娜刹什宝箱。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2145.jpeg" alt="图示：大草原神兽争夺战" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2146.jpeg" alt="图示：大草原神兽争夺战" loading="lazy"></figure><h3 id="注意" tabindex="-1">注意！！！ <a id="s185-ee84678f"></a> <a class="header-anchor" href="#注意" aria-label="Permalink to &quot;注意！！！ &lt;a id=&quot;s185-ee84678f&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>不管是娜刹什入侵还是神兽争夺战，在快胜利时都不能跳门，否则可能因为过图导致错失胜利的箱子奖励！</p><h2 id="_2-3-12-原大陆住民活动任务" tabindex="-1">2.3.12 原大陆住民活动任务 <a id="s186-8ca774b0"></a> <a class="header-anchor" href="#_2-3-12-原大陆住民活动任务" aria-label="Permalink to &quot;2.3.12 原大陆住民活动任务 &lt;a id=&quot;s186-8ca774b0&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>3 阶段之前，只有提交箱子袋子和该地图50 怪的任务，3 阶段后会有一个挖尸体（给该地图贡献）的任务。</p><p>住民活动任务可以在每个地图的前线基地处接取，如下：</p><p>在红框处NPC 可以接取击杀50 怪的活动任务。</p><p>如果地图处于3 阶段，则可在同NPC 处接取清扫任务，如下：</p><p>红框为接任务NPC，蓝框内的F 为远大路3 阶段住民开启的小繁荣，效果弱于英雄在势力主城开启的繁荣，不过只要地图还在3 阶段就可以随时来摸，非常方便。</p><p>清扫任务如下：</p><p>清扫尸体时还可以获得地图贡献。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2153.jpeg" alt="图示：2.3.12 原大陆住民活动任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2154.jpeg" alt="图示：2.3.12 原大陆住民活动任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2160.jpeg" alt="图示：2.3.12 原大陆住民活动任务" loading="lazy"></figure><h2 id="_2-3-13-公会日常活动任务" tabindex="-1">2.3.13 公会日常活动任务 <a id="s187-e25fea78"></a> <a class="header-anchor" href="#_2-3-13-公会日常活动任务" aria-label="Permalink to &quot;2.3.13 公会日常活动任务 &lt;a id=&quot;s187-e25fea78&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>公会日常活动任务在会长开启后（对公会等级和经验有要求），可以在各个地图的远征队管理员处接到任务，NPC 如下：</p><p>找到5 个远大路琥珀：</p><p>找5 个远大路水桶或者书籍下的宝箱：</p><p>任务奖励的袋子，可以开出随机BUFF。</p><p>参加征兆：</p><p>参加黄金或者芦苇地击杀75 怪：</p><p>击杀40H 关底BOSS：</p><p>任务奖励箱子自选内容：</p><p>击杀鲸鱼BOSS 扎卡鲁：</p><p>击杀烛台活动小怪：</p><p>击杀永恒之岛BOSS：</p><p>征兆任务奖励的英文名字的炼金材料可以制作新月紫石晶，如下：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2165.jpeg" alt="图示：2.3.13 公会日常活动任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2166.jpeg" alt="图示：2.3.13 公会日常活动任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2172.jpeg" alt="图示：2.3.13 公会日常活动任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2173.jpeg" alt="图示：2.3.13 公会日常活动任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2178.jpeg" alt="图示：2.3.13 公会日常活动任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2179.jpeg" alt="图示：2.3.13 公会日常活动任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2180.jpeg" alt="图示：2.3.13 公会日常活动任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2181.jpeg" alt="图示：2.3.13 公会日常活动任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2182.jpeg" alt="图示：2.3.13 公会日常活动任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2187.jpeg" alt="图示：2.3.13 公会日常活动任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2188.jpeg" alt="图示：2.3.13 公会日常活动任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2193.jpeg" alt="图示：2.3.13 公会日常活动任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2194.jpeg" alt="图示：2.3.13 公会日常活动任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2199.jpeg" alt="图示：2.3.13 公会日常活动任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2200.jpeg" alt="图示：2.3.13 公会日常活动任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2205.jpeg" alt="图示：2.3.13 公会日常活动任务" loading="lazy"></figure><h2 id="_2-3-14-娜刹什之证商人与娜刹什入侵胜利商人" tabindex="-1">2.3.14 娜刹什之证商人与娜刹什入侵胜利商人 <a id="s188-5257b5e1"></a> <a class="header-anchor" href="#_2-3-14-娜刹什之证商人与娜刹什入侵胜利商人" aria-label="Permalink to &quot;2.3.14 娜刹什之证商人与娜刹什入侵胜利商人 &lt;a id=&quot;s188-5257b5e1&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>娜刹什之证商人可以在势力主城处和浮空岛处找到，如下：</p><p>娜刹什之证商人商店内可购买道具每日刷新购买次数，推荐购买东西如下：</p><p>娜刹什入侵胜利商人会在娜刹什入侵胜利后刷新在机甲兵团支部，每日每个角色随机刷新可购买道具。包括伊弗南的勇气、伊弗南的忍耐、伊弗南的智慧、太初古代经验瓶子、太初BOSS 经验瓶子、二阶段突破石。</p><p>在升星毕业前不建议换BOSS 经验瓶子，毕业后可以囤个几千币，刷新就换去卖钱，一个能卖3-4W 金。</p><p>太初古代经验瓶子不推荐换，纯纯的垃圾，浪费币的。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2210.jpeg" alt="图示：2.3.14 娜刹什之证商人与娜刹什入侵胜利商人" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2211.jpeg" alt="图示：2.3.14 娜刹什之证商人与娜刹什入侵胜利商人" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2217.jpeg" alt="图示：2.3.14 娜刹什之证商人与娜刹什入侵胜利商人" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2222.jpeg" alt="图示：2.3.14 娜刹什之证商人与娜刹什入侵胜利商人" loading="lazy"></figure><h2 id="_2-3-15-每日任务概率刷新的海虫刷新点" tabindex="-1">2.3.15 每日任务概率刷新的海虫刷新点 <a id="s189-2351b3d0"></a> <a class="header-anchor" href="#_2-3-15-每日任务概率刷新的海虫刷新点" aria-label="Permalink to &quot;2.3.15 每日任务概率刷新的海虫刷新点 &lt;a id=&quot;s189-2351b3d0&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>寂静之海：</p><p>迷途之海：</p><p>黄金之海：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2223.jpeg" alt="图示：2.3.15 每日任务概率刷新的海虫刷新点" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2229.jpeg" alt="图示：2.3.15 每日任务概率刷新的海虫刷新点" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2230.jpeg" alt="图示：2.3.15 每日任务概率刷新的海虫刷新点" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2235.jpeg" alt="图示：2.3.15 每日任务概率刷新的海虫刷新点" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2236.jpeg" alt="图示：2.3.15 每日任务概率刷新的海虫刷新点" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2242.jpeg" alt="图示：2.3.15 每日任务概率刷新的海虫刷新点" loading="lazy"></figure><h2 id="_2-3-16-幽灵船" tabindex="-1">2.3.16 幽灵船 <a id="s190-5f16d9b6"></a> <a class="header-anchor" href="#_2-3-16-幽灵船" aria-label="Permalink to &quot;2.3.16 幽灵船 &lt;a id=&quot;s190-5f16d9b6&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>击杀幽灵船可以完成每日德翡纳之星的任务，在残骸处宝箱内可以获得石板，石板可以去自由岛或者双冠丘陵贩卖得到黑炭。</p><p>幽灵船只在迷途之海刷新6 个，被打后1 小时后刷新。</p><p>刷新位置如下：</p><p>幽灵船打掉后会有2 个宝箱，水面上的是船图纸和藏宝图，水下的是石板，如右</p><p>图：</p><p>双冠贩卖位置如下图：</p><p>NPC 如下：</p><p>石板贩卖收益受到摸箱子时和贩卖时的经商熟练度影响，27.2W 熟练度如下：</p><p>邮件实际收益（似乎可以讲价？）如下：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2243.jpeg" alt="图示：2.3.16 幽灵船" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2249.jpeg" alt="图示：2.3.16 幽灵船" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2254.jpeg" alt="图示：2.3.16 幽灵船" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2255.jpeg" alt="图示：2.3.16 幽灵船" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2260.jpeg" alt="图示：2.3.16 幽灵船" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2261.jpeg" alt="图示：2.3.16 幽灵船" loading="lazy"></figure><h2 id="_2-3-17-海盗藏宝图每日" tabindex="-1">2.3.17 海盗藏宝图每日 <a id="s191-e32cf478"></a> <a class="header-anchor" href="#_2-3-17-海盗藏宝图每日" aria-label="Permalink to &quot;2.3.17 海盗藏宝图每日 &lt;a id=&quot;s191-e32cf478&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>海盗每日给斑驳的新月硬币，可用来换称号或者外观。硬币如下图：</p><p>获取新月硬币的每日任务可以在海盗老巢的NPC 处接取，如下图：</p><p>对话接取任务后，去咆哮岛回城点附近找NPC。</p><p>找到红框内NPC 后并于之对话后，按F 与NPC 旁边红圈内水壶交互，如下图然后回到大厅和最开始的NPC 对话，此时你背包里应该会有一张藏宝图，接下来前往藏宝图坐标位置与藏宝箱交互即可。（坐标基本就那么几个位置，做多几次你</p><p>都能背下来）</p><p>找到藏宝箱后再次回到海盗大厅找最开始接任务的NPC 交任务就行。</p><p>藏宝箱随机给1-2 个新月硬币，必定至少会出2 个币，但其中一个概率是德翡纳星星，所以每天只能获得1-2 个新月硬币。（本人最高出过2 个新月币+1 个德翡纳星</p><p>星）</p><p>坐标处获得的宝箱如下图：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2266.jpeg" alt="图示：2.3.17 海盗藏宝图每日" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2267.jpeg" alt="图示：2.3.17 海盗藏宝图每日" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2273.jpeg" alt="图示：2.3.17 海盗藏宝图每日" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2274.jpeg" alt="图示：2.3.17 海盗藏宝图每日" loading="lazy"></figure><h2 id="_2-3-18-海盗每日" tabindex="-1">2.3.18 海盗每日 <a id="s192-d6df310f"></a> <a class="header-anchor" href="#_2-3-18-海盗每日" aria-label="Permalink to &quot;2.3.18 海盗每日 &lt;a id=&quot;s192-d6df310f&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>待更新</p>',273)])])}const m=a(t,[["render",e]]);export{d as __pageData,m as default};
